import React from "react";
import { User } from "../types";
import { FC } from "react";
interface UserTableProps {
  users: User[];
  filterText: string;
}

const UserTable: FC<UserTableProps> = ({ users, filterText }) => {
  if (users.length === 0) {
    return <div>таких нет "{filterText}"</div>;
  }

  return (
    <table className="user-table">
      <thead>
        <tr>
          <th>Name</th>
          <th>Picture</th>
          <th>Location</th>
          <th>Email</th>
          <th>Phone</th>
          <th>Registered</th>
        </tr>
      </thead>
      <tbody>
        {users.map((user, idx) => {
          const fullName = `${user.name.first} ${user.name.last}`;
          const location = `${user.location.state}, ${user.location.city}`;
          const registeredDate = new Date(
            user.registered.date,
          ).toLocaleDateString("ru-RU");
          return (
            <tr key={idx}>
              <td>{fullName}</td>
              <td className="picture-cell">
                <div className="picture-container">
                  <img src={user.picture.thumbnail} alt="thumbnail" />
                  <div className="tooltip">
                    <img src={user.picture.large} alt="large" />
                  </div>
                </div>
              </td>
              <td>{location}</td>
              <td>{user.email}</td>
              <td>{user.phone}</td>
              <td>{registeredDate}</td>
            </tr>
          );
        })}
      </tbody>
    </table>
  );
};

export default UserTable;
